sql:
SELECT * 
FROM data_correlation 
WHERE substation_id = 5678;

SELECT location, COUNT(*) AS substation_count
FROM substations
GROUP BY location;

SELECT substation_id
FROM substation_data
WHERE voltage_level = 'low voltage';

SELECT COUNT(*) AS total_load_shedding_events
FROM substation_data
WHERE load_shedding_status = 1;

external_knowledge:
- "daytime hours" refers to the business hours from 8 AM to 6 PM;
- The power generation figures are averaged per hour of the day;
- The question specifically seeks data from Substation 1.

sql:
SELECT substations.substation_name, substation_data.load_shedding_status
FROM substations
INNER JOIN substation_data ON substations.substation_id = substation_data.substation_id;

SELECT c.correlation_score, c.confidence_interval
FROM data_correlation c
WHERE c.substation_id = 'specific_substation_id';

SELECT COUNT(DISTINCT r.created_by) AS unique_user_count
FROM reports r
WHERE r.report_date >= DATE('now', '-7 days');
